function VersionBadge({ version }) {
  return (
    <span style={{
      display: 'inline-block',
      background: 'linear-gradient(135deg, #60A5FA 0%, #A78BFA 100%)',
      color: '#fff', fontFamily: T.monoFont, fontSize: 13, fontWeight: 700,
      padding: '4px 12px', borderRadius: 6, letterSpacing: '0.02em',
    }}>
      v{version}
    </span>
  )
}

